INSERT INTO "historial_conversacion" ("id", "id_estudiante", "telegram_id", "pregunta", "respuesta", "intencion", "sesion_id", "tokens_usados", "timestamp") VALUES
(1,	'20250001',	100001,	'¿Qué cursos me faltan para completar la ruta digital?',	'Hola Valentina 👋 Revisé tu progreso: tienes aprobados HECO (Pilar 1) y TINF (Pilar 3). Solo te falta un curso del Pilar 2 (Analítica y Contenido Digital). Puedes escoger entre: Habilidades en Analítica Digital, Marca Personal Digital o Creación de Contenidos Digitales.',	'consulta_cursos_faltantes',	'sess_100001_20260320',	420,	'2026-03-29 03:40:16.792391'),
(2,	'20220003',	100003,	'Ya terminé todos mis cursos, ¿estoy al día?',	'Perfecto Laura 🎉 Tu ruta de Competencias Digitales está 100% completada. Aprobaste los 5 cursos del plan antiguo y los tres pilares están cubiertos por homologación.',	'consulta_progreso',	'sess_100003_20260318',	310,	'2026-03-29 03:40:16.792391'),
(3,	'20250007',	100007,	'Hola, ¿cómo puedo matricular un curso de competencias digitales?',	'Hola Camila! Las inscripciones para el periodo de cursos intensivos (15 de abril al 15 de mayo de 2026) están abiertas del 27 de marzo al 9 de abril de 2026. El pago de matrícula debe realizarse antes del 9 de abril a las 5:00 p.m. ¿Quieres ver los cursos disponibles?',	'matricular_curso',	'sess_100007_20260325',	380,	'2026-03-29 03:40:16.792391'),
(4,	'20240012',	100012,	'Quiero presentar validación de IA Generativa',	'Claro Nicolás, puedo ayudarte a agendar tu prueba de validación para IA Generativa. ¿Qué fecha te quedaría mejor para presentarla?',	'agendar_validacion',	'sess_100012_20260322',	290,	'2026-03-29 03:40:16.792391'),
(5,	NULL,	8263260613,	'mi nombre es alfredo diaz',	'¡Hola Alfredo Díaz! Soy el asistente del Centro de Competencias Digitales (CCD) de la Universidad Autónoma de Bucaramanga. ¿En qué puedo ayudarte hoy?',	'saludo',	'tg:8263260613',	NULL,	'2026-03-29 22:02:17.857321'),
(6,	NULL,	8263260613,	'mi nombre es alfredo diaz',	'¡Hola, Alfredo Díaz! Soy tu asistente del Centro de Competencias Digitales (CCD) de la Universidad Autónoma de Bucaramanga (UNAB). ¿En qué puedo ayudarte hoy?',	'saludo',	'tg:8263260613',	NULL,	'2026-03-29 22:05:21.098107'),
(7,	NULL,	8263260613,	'mi nombre es alfredo diaz',	'¡Hola Alfredo! Soy tu asistente del Centro de Competencias Digitales (CCD) de la UNAB. Estoy aquí para ayudarte con cualquier duda que tengas. ¿En qué puedo ayudarte hoy?',	'saludo',	'tg:8263260613',	0,	'2026-03-29 22:07:13.963873'),
(8,	NULL,	8263260613,	'mi nombre es alfredo diaz',	'¡Hola Alfredo! Soy tu asistente del Centro de Competencias Digitales (CCD) de la UNAB. Estoy aquí para ayudarte con cualquier duda que tengas. ¿En qué puedo ayudarte hoy?',	'saludo',	'tg:8263260613',	0,	'2026-03-29 22:09:04.522882'),
(9,	NULL,	8263260613,	'mi nombre es alfredo diaz',	'¡Hola, Alfredo Diaz! Soy el asistente del Centro de Competencias Digitales (CCD) de la UNAB. ¿En qué puedo ayudarte hoy?',	'saludo',	'tg:8263260613',	0,	'2026-03-29 22:13:23.389766'),
(10,	NULL,	8263260613,	'Si quero saber que son las competencias digitales',	'Las competencias digitales se refieren a la capacidad de utilizar tecnologías digitales de manera eficiente y efectiva. Incluyen habilidades para buscar, evaluar, utilizar y crear información a través de internet y otras herramientas digitales. En la Ruta de Competencias Digitales del CCD, se busca que los estudiantes desarrollen estas habilidades para mejorar su aprendizaje y desempeño profesional. 

En general, las competencias digitales abarcan áreas como el uso de software, manejo de datos, y la comprensión de la seguridad digital y la ética en el entorno digital. 

¿Tienes otra consulta o hay algo más en lo que te pueda ayudar?',	'consulta_general',	'tg:8263260613',	0,	'2026-03-29 22:14:06.766988'),
(11,	'20250001',	8263260613,	'mi is es 20250001',	'Hola Valentina Gómez Rincón, eres estudiante del programa de **Ingeniería de Sistemas** y actualmente te encuentras en el **semestre 2**. Aquí tienes un resumen de tus notas hasta el momento:

1. **Interacción Digital**  
   - **Código**: HECO  
