(166,	NULL,	NULL,	'31600560056',	'He registrado tu número de celular 31600560056 y pronto un agente se pondrá en contacto contigo para atender tus consultas. Si necesitas algo más, no dudes en decírmelo. ¡Estoy aquí para ayudarte!',	NULL,	'4364d1ef-e32c-4aff-a0aa-82d4214e48c3',	NULL,	'2026-04-07 19:05:10.613982'),
