(418,	NULL,	NULL,	'Cuál es el mejor profesor ',	'Lamentablemente, no tengo acceso a información específica sobre profesores o sus evaluaciones. Te recomiendo hablar con otros estudiantes o consultar entre tus compañeros para obtener sus opiniones sobre los profesores y sus metodologías de enseñanza.',	NULL,	'2ee03a4e-a3fc-40f8-b1d2-a2fbce338929',	NULL,	'2026-04-23 20:57:57.599453'),
(419,	NULL,	NULL,	'como es mi cumplimiento en comptencias digitales',	'Parece que no has proporcionado tu ID de estudiante. Si me proporcionas tu ID, puedo consultar tu progreso en competencias digitales.',	NULL,	'a618692f-4692-44a2-b16b-75269ebcdea9',	NULL,	'2026-04-23 20:57:57.894094'),
(423,	NULL,	NULL,	'Cuales son mis notas U00171819',	'Parece que el ID que has proporcionado (U00171819) no se encuentra en nuestra base de datos. Te sugiero que verifiques el ID o contactes a los administradores para obtener más ayuda sobre tu progreso académico.',	NULL,	'2ee03a4e-a3fc-40f8-b1d2-a2fbce338929',	NULL,	'2026-04-23 20:58:16.022327'),
